class Solution:
    def minFallingPathSum(self, matrix: list[list[int]]) -> int:
        n_rows = len(matrix)
        n_cols = len(matrix[0])

        if n_rows == 1:
            return min(matrix[0])

        for r in range(1, n_rows):
            for c in range(n_cols):
                # Calculate the minimum sum from the previous row
                # that can lead to the current cell (r, c)

                # Start with the direct top element
                min_prev_row_val = matrix[r-1][c]

                # Check top-left element if it exists
                if c > 0:
                    min_prev_row_val = min(min_prev_row_val, matrix[r-1][c-1])

                # Check top-right element if it exists
                if c < n_cols - 1:
                    min_prev_row_val = min(min_prev_row_val, matrix[r-1][c+1])

                # Update the current cell with the sum of its value and the minimum
                # falling path sum from the previous row
                matrix[r][c] += min_prev_row_val

        # The minimum falling path sum will be the minimum value in the last row
        return min(matrix[n_rows - 1])
